sys_security_acl.script:
var user = gs.getUser();
var assignment_group = current.getDisplayValue('assignment_group') || '';
var primary_office = current.getValue('primary_office') || '';
var allow = false;
// DFCT0011821 - top check is only for restricted group now
if(assignment_group != ''){
	// DFCT0011824 
	allow = user.isMemberOf(assignment_group);
} else{
	allow = new task_privacy().userCanAccessOU(primary_office);
}
answer = allow;
